class Solution:
    def findTheLongestBalancedSubstring(self, s: str) -> int:
        n = len(s)
        if n == 0:
            return 0

        zero_counts = [0] * n
        one_counts = [0] * n

        # Compute zero_counts
        for i in range(n-1, -1, -1):
            if s[i] == '0':
                zero_counts[i] = zero_counts[i+1] + 1 if i+1 < n else 1
            else:
                zero_counts[i] = 0

        # Compute one_counts
        for i in range(n-1, -1, -1):
            if s[i] == '1':
                one_counts[i] = one_counts[i+1] + 1 if i+1 < n else 1
            else:
                one_counts[i] = 0

        max_len = 0

        for i in range(n):
            if s[i] == '0':
                count0 = zero_counts[i]
                start = i + count0
                if start >= n:
                    continue
                count1 = one_counts[start]
                k = min(count0, count1)
                current_len = 2 * k
                if current_len > max_len:
                    max_len = current_len

        return max_len if max_len > 0 else 0

